     * findNthLeapYear(2000, 4) => 2008
     * findNthLeapYear(1996, 10) => 2032
     */
    public static int findNthLeapYear(int Y, int N)  {
        // Initialize the current year to the start year
        int currentYear = Y;

        // Initialize the position of the leap year to 0
