      } else {
        symmetric[i] = (int) (9 * Math.pow(10, (n - i - 1) / 2)) - 1;
      }
    }

    List<String> result = new ArrayList<>();
    for (int i = 0; i < n; i++) {
      result.add(String.valueOf(symmetric[i]));
    }
    return result;
  }

