  // To avoid division by zero, we'll cross-multiply to compare the slopes.
  int slope1 = (y2 - y1) * (x3 - x1);
  int slope2 = (y3 - y1) * (x2 - x1);

  // The points form a boomerang if the slopes are not equal.
  return slope1 != slope2;
}

