import java.util.ArrayList;
import java.util.List;

public class Solution {

  /**
   * Return all integers in the range [1, n] in lexicographical order.
   *
   * @param n The upper limit of the range.
   * @return List of integers in lexicographical order.
   *
   * Example:
   * lexicalOrder(13)
   * Output: [1,10,11,12,13,2,3,4,5,6,7,8,9]
   */
  public static List<Integer> lexicalOrder(int n)  {
    if (n <= 0) {
      return new ArrayList<>();
    }
    List<Integer> result = new ArrayList<>();
    for (int i = 1; i <= 9; i++) {
      backtrack(result, i, n, 1);
    }
    return result;
  }

  private static void backtrack(List<Integer> result, int digit, int n, int pos) {
    if (digit > n) {
      return;
    }
    result.add(digit);
    for (int i = 0; i < 10; i++) {
      if (pos * 10 + i <= n) {
        backtrack(result, pos * 10 + i, n, pos * 10 + i);
      }
    }
  }

  public static void main(String[] args) {
    List<Integer> result = lexicalOrder(13);
    for (Integer i : result) {
      System.out.print(i + " ");
    }
  }
}

